export const getStickerById = (id) => STICKERS.find((sticker) => sticker.id === id);
export const getStickersByTeam = (teamCode) => STICKERS.filter((sticker) => sticker.teamCode === teamCode);
export const getStickersByGroup = (group) => STICKERS.filter((sticker) => sticker.group === group);
export const getStickersByType = (type) => STICKERS.filter((sticker) => sticker.type === type);

export const validateStickerSeed = () => ({
  total: STICKERS.length,
  common: STICKERS.filter((sticker) => sticker.type === STICKER_TYPES.COMMON).length,
  specialFoil: STICKERS.filter((sticker) => sticker.type === STICKER_TYPES.SPECIAL_FOIL).length,
  uniqueIds: new Set(STICKERS.map((sticker) => sticker.id)).size,
  hasDuplicateIds: new Set(STICKERS.map((sticker) => sticker.id)).size !== STICKERS.length,
  todo: STICKERS.filter((sticker) => sticker.playerName.startsWith('TODO:')).map((sticker) => sticker.id),
});
